/**
 * A hollow, bottle-shaped vase oriented upright along the Z-axis,
 * generated by unioning parametric cylinders and subtracting an inner cavity.
 */

// Define parameters for customizability in ForgeCAD Studio
const base_radius = Param.number("Base Radius", 25, { min: 10, max: 100, unit: "mm" });
const belly_radius = Param.number("Belly Radius", 28, { min: 10, max: 100, unit: "mm" });
const shoulder_radius = Param.number("Shoulder Radius", 22, { min: 5, max: 100, unit: "mm" });
const neck_radius = Param.number("Neck Radius", 10, { min: 3, max: 50, unit: "mm" });
const wall_thickness = Param.number("Wall Thickness", 2, { min: 0.5, max: 10, unit: "mm" });

// Calculate intermediate transition radii for a smoother profile
const r2 = (base_radius + belly_radius) / 2;
const r4 = (belly_radius + shoulder_radius) / 2;
const r6 = (shoulder_radius + neck_radius) / 2;

// Construct outer segments using stacked cylinders
const C1 = cylinder(5, base_radius);
const C2 = cylinder(10, r2).translate(0, 0, 5);
const C3 = cylinder(10, belly_radius).translate(0, 0, 15);
const C4 = cylinder(10, r4).translate(0, 0, 25);
const C5 = cylinder(10, shoulder_radius).translate(0, 0, 35);
const C6 = cylinder(10, r6).translate(0, 0, 45);
const C7 = cylinder(10, neck_radius).translate(0, 0, 55);

// Combine the outer segments into a single solid body
const outer = C1.union(C2).union(C3).union(C4).union(C5).union(C6).union(C7);

// Construct inner segments, offset by the wall thickness
const IC1 = cylinder(3, base_radius - wall_thickness).translate(0, 0, 2);
const IC2 = cylinder(10, r2 - wall_thickness).translate(0, 0, 5);
const IC3 = cylinder(10, belly_radius - wall_thickness).translate(0, 0, 15);
const IC4 = cylinder(10, r4 - wall_thickness).translate(0, 0, 25);
const IC5 = cylinder(10, shoulder_radius - wall_thickness).translate(0, 0, 35);
const IC6 = cylinder(10, r6 - wall_thickness).translate(0, 0, 45);
const IC7 = cylinder(12, neck_radius - wall_thickness).translate(0, 0, 55);

// Combine the inner segments to form the negative cavity
const inner = IC1.union(IC2).union(IC3).union(IC4).union(IC5).union(IC6).union(IC7);

// Subtract the cavity from the outer shell to produce the open hollow vase
const vase = outer.subtract(inner).color("#c58c73");

// Return the final assembly object
return {
  "a-hollow,-bottle-shaped-vase-oriented-up": vase,
};
